-- =====================================================================
-- BUSINESS OBJECT / DATA PRODUCT: Renters Insurance Policy (v1)
-- REGION: europe-west1
-- STANDARDS: ACORD / Insurance & Financial Services Reference Model
-- =====================================================================

-- 1. DATASET CREATION
-- We establish the schema acting as our self-contained Data Product container.
CREATE SCHEMA IF NOT EXISTS `renters_insurance_v1`
OPTIONS (
  location = "europe-west1",
  description = "Domain-driven data product representing Renters Insurance policies, covering customer demographic profiles, rented physical properties, and active contractual insurance terms."
);

-- 2. DDL: CUSTOMERS DIMENSION (INSURED PARTY)
CREATE OR REPLACE TABLE `renters_insurance_v1.customers` (
  customer_id STRING OPTIONS(description="Globally unique identifier for the customer (renter)"),
  first_name STRING OPTIONS(description="First name of the primary insured individual"),
  last_name STRING OPTIONS(description="Last name of the primary insured individual"),
  email STRING OPTIONS(description="Primary communication and billing email address"),
  phone STRING OPTIONS(description="Contact phone number in international format"),
  date_of_birth DATE OPTIONS(description="Date of birth of the primary insured used for age-rating risk assessment"),
  created_at TIMESTAMP OPTIONS(description="UTC timestamp when the customer's customer-relationship-management profile was established"),
  PRIMARY KEY (customer_id) NOT ENFORCED
)
OPTIONS (
  description = "Dimension table maintaining demographics and personal identifier profiles of primary insured policyholders."
);

-- 3. DDL: PROPERTIES DIMENSION (PHYSICAL RISK LOCATIONS)
CREATE OR REPLACE TABLE `renters_insurance_v1.properties` (
  property_id STRING OPTIONS(description="Globally unique identifier for the rented physical location"),
  address_line1 STRING OPTIONS(description="Street and building number details of the physical property"),
  city STRING OPTIONS(description="City where the rented dwelling is located"),
  state_province STRING OPTIONS(description="Standard state or provincial abbreviation (e.g., CA, TX)"),
  postal_code STRING OPTIONS(description="Postal/ZIP code of the physical property"),
  country STRING OPTIONS(description="Two-letter ISO 3166-1 country code"),
  property_type STRING OPTIONS(description="Architectural structure type: Apartment, Condo, Townhouse, Single-Family"),
  construction_year INT64 OPTIONS(description="The year the residential structure was built"),
  has_fire_alarm BOOL OPTIONS(description="Premium-credit flag indicating active central-station fire alarm systems"),
  has_security_system BOOL OPTIONS(description="Premium-credit flag indicating active intruder or burglar alarm systems"),
  has_sprinklers BOOL OPTIONS(description="Premium-credit flag indicating active indoor fire suppression sprinklers"),
  PRIMARY KEY (property_id) NOT ENFORCED
)
OPTIONS (
  description = "Dimension table containing architectural characteristics, locations, and security features of physical rented properties."
);

-- 4. DDL: POLICIES FACT (INSURANCE CONTRACT)
CREATE OR REPLACE TABLE `renters_insurance_v1.policies` (
  policy_id STRING OPTIONS(description="Globally unique identifier for the renters policy contract"),
  policy_number STRING OPTIONS(description="Human-readable business key identifier for the contract file"),
  customer_id STRING OPTIONS(description="Foreign key linking the contract back to the primary insured customer"),
  property_id STRING OPTIONS(description="Foreign key linking the contract to the physical risk location"),
  effective_date DATE OPTIONS(description="The calendar date on which contract coverage begins"),
  expiration_date DATE OPTIONS(description="The calendar date on which contract coverage expires"),
  policy_status STRING OPTIONS(description="Active operational state of the policy: ACTIVE, CANCELLED, LAPSED, EXPIRED"),
  personal_property_limit NUMERIC OPTIONS(description="Coverage limit for tenant's personal property/belongings inside the residence (USD)"),
  personal_liability_limit NUMERIC OPTIONS(description="Coverage limit for legal liability claims against the renter (USD)"),
  loss_of_use_limit NUMERIC OPTIONS(description="Coverage limit for additional living expenses if the unit is uninhabitable (USD)"),
  deductible NUMERIC OPTIONS(description="The standard out-of-pocket amount paid by the insured before policy coverage takes effect (USD)"),
  annual_premium NUMERIC OPTIONS(description="Calculated gross annual premium of the coverage package (USD)"),
  created_at TIMESTAMP OPTIONS(description="UTC timestamp when this policy contract record was legally bound"),
  PRIMARY KEY (policy_id) NOT ENFORCED,
  CONSTRAINT fk_customer FOREIGN KEY (customer_id) REFERENCES `renters_insurance_v1.customers`(customer_id) NOT ENFORCED,
  CONSTRAINT fk_property FOREIGN KEY (property_id) REFERENCES `renters_insurance_v1.properties`(property_id) NOT ENFORCED
)
OPTIONS (
  description = "Central transactional fact table recording legally bound Renters Insurance contracts, coverage bounds, and premium values."
);


